<section class="section"><div class="container"><h1>Search</h1><form method="GET" action="/search"><input type="search" name="q" value="<?= h($query ?? '') ?>" placeholder="Search cases, articles, districts..." class="search-input-large"><button type="submit" class="btn btn-primary">Search</button></form><?php if ($query && !empty($results)): ?><div class="search-results"><?php foreach ($results as $r): ?><article class="search-result"><a href="/<?= h($r['type']) ?>s/<?= h($r['slug']) ?>"><h3>[<?= h(ucfirst($r['type'])) ?>] <?= h($r['title']) ?></h3><?php if (!empty($r['excerpt'])): ?><p><?= h(truncate($r['excerpt'], 200)) ?></p><?php endif; ?></a></article><?php endforeach; ?></div><?php elseif ($query): ?><p>No results found for "<?= h($query) ?>".</p><?php endif; ?></div></section>
